class Solution {
    public long minimumCost(String s) {
        int n = s.length();
        int[] dp = new int[n];

        for (int i = 0; i < n; i++) {
            dp[i] = s.charAt(i) == '0' ? 1 : 0;
        }

        for (int i = 1; i < n; i++) {
            for (int j = i; j < n; j++) {
                dp[j] = Math.min(dp[j], dp[j - 1] + 1);
            }
        }

        return dp[n - 1];
    }
}
```

